import type { Application, Request, Response } from 'express';
import { db } from '../../core/db.js';
import { StructuredLogger } from '../../utils/structured-logger.js';
import { config } from '../../config/index.js';

/**
 * Stats endpoint that returns read-only system counters
 *
 * Returns:
 * - uptime_seconds: Server uptime in seconds
 * - memory_rss_bytes: RSS memory usage from process.memoryUsage()
 * - db_rows_atoms: Row count in atoms table
 * - db_rows_molecules: Row count in molecules table
 * - db_rows_tags: Row count in tags table
 * - search_count: Total number of search requests (from counter)
 * - ingest_count: Total number of ingest requests (from counter)
 */

// Global counter storage
const counters = {
  search_count: 0,
  ingest_count: 0,
} as const;

export function setupStatsRoutes(app: Application) {
  app.get('/v1/stats', async (_req: Request, res: Response) => {
    try {
      // Get server uptime
      const serverStartTime = config.START_TIME || Date.now() - 86400000; // Default to 24h if not set
      const uptime_seconds = Math.floor((Date.now() - serverStartTime) / 1000);

      // Get memory usage
      const memoryUsage = process.memoryUsage();
      const memory_rss_bytes = memoryUsage.rss;

      // Get database row counts safely
      const dbRows = await Promise.all([
        db.run('SELECT COUNT(*) as count FROM atoms'),
        db.run('SELECT COUNT(*) as count FROM molecules'),
        db.run('SELECT COUNT(*) as count FROM tags'),
      ]);

      const db_rows_atoms = dbRows[0].rows[0].count || 0;
      const db_rows_molecules = dbRows[1].rows[0].count || 0;
      const db_rows_tags = dbRows[2].rows[0].count || 0;

      // Return stats
      res.json({
        uptime_seconds,
        memory_rss_bytes,
        db_rows_atoms,
        db_rows_molecules,
        db_rows_tags,
        search_count: counters.search_count,
        ingest_count: counters.ingest_count,
      });
    } catch (error: any) {
      StructuredLogger.error('STATS_GET_ERROR', { error: error.message });
      res.status(500).json({
        error: 'Failed to retrieve system stats',
        message: error.message,
      });
    }
  });
}
